// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{})
}

// ServeMux is an abstraction of http.ServeMux.
type ServeMux interface {
	HandleFunc(pattern string, handler func(http.ResponseWriter, *http.Request))
	ServeHTTP(w http.ResponseWriter, r *http.Request)
}

type StdHTTPServerOptions struct {
	BaseURL          string
	BaseRouter       ServeMux
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, m ServeMux) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseRouter: m,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc("GET "+options.BaseURL+"/courier/messages", wrapper.ListCourierMessages)
	m.HandleFunc("GET "+options.BaseURL+"/courier/messages/{id}", wrapper.GetCourierMessage)
	m.HandleFunc("GET "+options.BaseURL+"/health/alive", wrapper.GetHealthAlive)
	m.HandleFunc("GET "+options.BaseURL+"/health/ready", wrapper.GetHealthReady)
	m.HandleFunc("GET "+options.BaseURL+"/identities", wrapper.ListIdentities)
	m.HandleFunc("PATCH "+options.BaseURL+"/identities", wrapper.BatchPatchIdentities)
	m.HandleFunc("POST "+options.BaseURL+"/identities", wrapper.CreateIdentity)
	m.HandleFunc("DELETE "+options.BaseURL+"/identities/{id}", wrapper.DeleteIdentity)
	m.HandleFunc("GET "+options.BaseURL+"/identities/{id}", wrapper.GetIdentity)
	m.HandleFunc("PATCH "+options.BaseURL+"/identities/{id}", wrapper.PatchIdentity)
	m.HandleFunc("PUT "+options.BaseURL+"/identities/{id}", wrapper.UpdateIdentity)
	m.HandleFunc("DELETE "+options.BaseURL+"/identities/{id}/credentials/{type}", wrapper.DeleteIdentityCredentials)
	m.HandleFunc("DELETE "+options.BaseURL+"/identities/{id}/sessions", wrapper.DeleteIdentitySessions)
	m.HandleFunc("GET "+options.BaseURL+"/identities/{id}/sessions", wrapper.ListIdentitySessions)
	m.HandleFunc("GET "+options.BaseURL+"/organizations", wrapper.ListOrganizations)
	m.HandleFunc("POST "+options.BaseURL+"/organizations", wrapper.CreateOrganization)
	m.HandleFunc("DELETE "+options.BaseURL+"/organizations/{id}", wrapper.DeleteOrganization)
	m.HandleFunc("GET "+options.BaseURL+"/organizations/{id}", wrapper.GetOrganization)
	m.HandleFunc("PATCH "+options.BaseURL+"/organizations/{id}", wrapper.UpdateOrganization)
	m.HandleFunc("POST "+options.BaseURL+"/recovery/code", wrapper.CreateRecoveryCodeForIdentity)
	m.HandleFunc("POST "+options.BaseURL+"/recovery/link", wrapper.CreateRecoveryLinkForIdentity)
	m.HandleFunc("GET "+options.BaseURL+"/schemas", wrapper.ListIdentitySchemas)
	m.HandleFunc("GET "+options.BaseURL+"/schemas/{id}", wrapper.GetIdentitySchema)
	m.HandleFunc("GET "+options.BaseURL+"/sessions", wrapper.ListSessions)
	m.HandleFunc("DELETE "+options.BaseURL+"/sessions/{id}", wrapper.DisableSession)
	m.HandleFunc("GET "+options.BaseURL+"/sessions/{id}", wrapper.GetSession)
	m.HandleFunc("PATCH "+options.BaseURL+"/sessions/{id}/extend", wrapper.ExtendSession)

	return m
}

